const SUPPORTED_RATIOS = ['9:16', '4:5', '16:9'];

const TEMPLATE_MAP = {
  'multi item': 'ad-multi-item-1',
  'single item spotlight': 'ad-single-item-spotlight-1',
  'educational': 'organic-educational-1'
};

const PLATFORM_MAP = {
  'fb_feed': 'FACEBOOK',
  'fb_stories': 'FACEBOOK',
  'fb_reels': 'FACEBOOK',
  'ig_feed': 'INSTAGRAM',
  'ig_stories': 'INSTAGRAM',
  'ig_reels': 'INSTAGRAM',
  'tt_feed': 'TIKTOK',
  'yt_shorts': 'YOUTUBE',
  'yt_feed': 'YOUTUBE',
  'facebook': 'FACEBOOK',
  'instagram': 'INSTAGRAM',
  'tiktok': 'TIKTOK',
  'youtube': 'YOUTUBE'
};

const SUPPORTED_PLATFORMS = new Set(['TIKTOK', 'INSTAGRAM', 'FACEBOOK', 'YOUTUBE']);

// Same priority order as TEMP_002 in [02] Generate Script
const FEATURE_PRIORITY = [
  'engine_bay', 'moonroof', 'infotainment_360_camera',
  'infotainment_carplay', 'front_seats', 'steering_wheel',
  'instrument_cluster', 'cargo_area', 'second_row_seats',
  'third_row_seats', 'special_feature', 'infotainment_other'
];

const MAX_FEATURE_PHOTOS = 5; // hero + 5 features = 6 total

// Strip /thumb/ suffix for full-res URLs (same as getFullResUrl in TEMP_002)
function getFullResUrl(url) {
  if (!url) return url;
  return url.replace(/\/thumb\/?$/, '/');
}

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Build per-ratio platform mapping
  const ratioPlat = {};
  let ratios = [];

  if (d.placements) {
    const p = typeof d.placements === 'string' ? JSON.parse(d.placements) : d.placements;
    if (Array.isArray(p)) {
      for (const output of p) {
        const ratio = output.aspect_ratio;
        if (!ratio || !SUPPORTED_RATIOS.includes(ratio)) continue;
        if (!ratioPlat[ratio]) ratioPlat[ratio] = new Set();
        if (Array.isArray(output.platforms)) {
          for (const plat of output.platforms) {
            const mapped = PLATFORM_MAP[plat.toLowerCase()];
            if (mapped && SUPPORTED_PLATFORMS.has(mapped)) {
              ratioPlat[ratio].add(mapped);
            }
          }
        }
      }
      ratios = Object.keys(ratioPlat);
    }
  }

  if (ratios.length === 0) {
    ratios = ['9:16'];
    ratioPlat['9:16'] = new Set(['INSTAGRAM', 'FACEBOOK']);
  }

  const ratio_platforms = {};
  for (const [r, s] of Object.entries(ratioPlat)) {
    ratio_platforms[r] = [...s];
  }
  const allPlatforms = [...new Set(Object.values(ratio_platforms).flat())];

  const tn = (d.template_name || '').toLowerCase();
  const template_id = TEMPLATE_MAP[tn] || 'ad-multi-item-1';
  const isOrganic = template_id.startsWith('organic-');

  // Parse vehicles from enriched query
  let vehicles = [];
  if (d.vehicles) {
    vehicles = typeof d.vehicles === 'string' ? JSON.parse(d.vehicles) : d.vehicles;
  }

  // Use processed_items from the asset if available (has selected_photos, equipment, etc.)
  // Otherwise build a basic version from vehicles
  let assetProcessed = [];
  if (d.asset_processed_items) {
    assetProcessed = typeof d.asset_processed_items === 'string'
      ? JSON.parse(d.asset_processed_items)
      : d.asset_processed_items;
  }

  let processed_items;
  let selected_photos = [];

  if (Array.isArray(assetProcessed) && assetProcessed.length > 0) {
    // Use the prep phase processed_items (has selected_photos, equipment, etc.)
    processed_items = assetProcessed;

    // Extract selected_photos from first processed item (spotlight)
    const firstItem = assetProcessed[0];
    if (firstItem?.selected_photos) {
      const sp = firstItem.selected_photos;
      const vf = firstItem.verified_features || {};

      // Hero is always first
      const hero = sp.hero_exterior || null;
      if (hero) {
        selected_photos.push({
          photo_url: getFullResUrl(hero.photo_url),
          photo_index: hero.photo_index
        });
      }

      // Features: use priorityOrder, gate on verified_features having script_features,
      // limit to MAX_FEATURE_PHOTOS
      let featureCount = 0;
      for (const category of FEATURE_PRIORITY) {
        if (featureCount >= MAX_FEATURE_PHOTOS) break;
        // Must exist in both selected_photos AND verified_features with script_features
        if (sp[category] && vf[category]?.script_features) {
          selected_photos.push({
            photo_url: getFullResUrl(sp[category].photo_url),
            photo_index: sp[category].photo_index
          });
          featureCount++;
        }
      }
    }
  } else {
    // Build basic processed_items from vehicles
    processed_items = vehicles.map((v, idx) => ({
      item_id: v.item_id || null,
      vin: v.vin,
      year: v.year,
      make: v.make,
      model: v.model,
      trim: v.trim || '',
      body_style: v.body_style || '',
      price: v.price,
      mileage: v.mileage || 0,
      days_on_lot: v.days_on_lot || 0,
      photo_url: v.vin
        ? 'https://res.cloudinary.com/dtpqxuwby/image/upload/' + v.vin + '.png'
        : v.image_url || null,
      original_photo_url: v.image_url || null,
      bg_removed: !!v.vin,
      sort_order: v.sort_order ?? idx,
      equipment_highlights: [],
      mileage_category: 'average'
    }));
  }

  const vins = vehicles.map(v => v.vin).filter(Boolean);

  results.push({
    json: {
      client_id: d.client_id,
      client: d.client_slug,
      client_name: d.client_name,
      asset_id: d.asset_id,
      template_id: template_id,
      avatar_id: d.avatar_id || null,
      background_id: d.background_id || null,
      ratios: ratios,
      platforms: allPlatforms,
      ratio_platforms: ratio_platforms,
      email: 'system@ad-pilot.ai',
      source: 'weekly_cycle',
      skip_to_render: true,
      is_organic: isOrganic,
      phonetic_script: d.phonetic_script || null,
      script_text: d.script_text || null,
      vehicles: vehicles,
      vins: vins,
      processed_items: processed_items,
      _hasProcessedItems: processed_items.length > 0,
      selected_photos: selected_photos,
      music_id: d.music_id || null,
      media: {
        music_url: d.music_url || null
      }
    }
  });
}

return results;

const items = $input.all();
const allData = items[0]?.json?.data || [];
const jobs = allData.map(d => ({ asset_id: d.asset_id, job_id: d.job_id, status: d.status }));

return [{
  json: {
    success: true,
    message: `Triggered video generation for ${jobs.length} assets`,
    jobs: jobs,
    triggered_at: new Date().toISOString()
  }
}];

